import React, { useState, useEffect } from 'react';
import './css/GroceryList.css';

function GroceryList({ user }) {
  const [groceryLists, setGroceryLists] = useState([]);
  const [newItem, setNewItem] = useState('');
  const [newItemQuantity, setNewItemQuantity] = useState('');
  const [selectedListId, setSelectedListId] = useState(null);

  useEffect(() => {
    if (user) fetchGroceryLists();
  }, [user]);

  const fetchGroceryLists = async () => {
    try {
      const res = await fetch(`http://localhost:8000/groceryList/userID/${user.id || user._id}`);
      if (res.ok) {
        const data = await res.json();
        setGroceryLists(data);
        if (data.length > 0) setSelectedListId(data[0]._id);
      }
    } catch (err) {
      console.error('Fetch error:', err);
    }
  };

  const addItem = async () => {
    if (!newItem.trim() || !newItemQuantity.trim() || !selectedListId) return;
    try {
      const res = await fetch(`http://localhost:8000/groceryList/${selectedListId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: newItem.trim(), quantity: newItemQuantity.trim(), category: 'Other', checked: false }),
      });
      if (res.ok) {
        fetchGroceryLists();
        setNewItem('');
        setNewItemQuantity('');
      }
    } catch (err) {
      console.error('Add error:', err);
    }
  };

  const removeItem = async (itemName) => {
    try {
      await fetch(`http://localhost:8000/groceryList/${selectedListId}/${itemName}`, { method: 'DELETE' });
      fetchGroceryLists();
    } catch (err) {
      console.error('Remove error:', err);
    }
  };

  const selectedList = groceryLists.find((l) => l._id === selectedListId);

  return (
    <div className="page">
      <div className="page-header">
        <h1>Grocery List</h1>
      </div>

      {groceryLists.length > 1 && (
        <div className="grocery-tabs">
          {groceryLists.map((list) => (
            <button
              key={list._id}
              className={`grocery-tab${selectedListId === list._id ? ' grocery-tab--active' : ''}`}
              onClick={() => setSelectedListId(list._id)}
            >
              {list.name}
            </button>
          ))}
        </div>
      )}

      <div className="grocery-add">
        <input
          type="text"
          placeholder="Item name"
          value={newItem}
          onChange={(e) => setNewItem(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && addItem()}
        />
        <input
          type="text"
          placeholder="Qty"
          value={newItemQuantity}
          onChange={(e) => setNewItemQuantity(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && addItem()}
          className="grocery-qty"
        />
        <button className="btn-primary" onClick={addItem}>Add</button>
      </div>

      <div className="grocery-items">
        {!selectedList || selectedList.items.length === 0 ? (
          <p className="grocery-empty">No items yet.</p>
        ) : (
          selectedList.items.map((item, idx) => (
            <div key={idx} className="grocery-item">
              <span className="grocery-item-name">{item.name}</span>
              <span className="grocery-item-qty">{item.quantity}</span>
              <button className="grocery-remove" onClick={() => removeItem(item.name)}>✕</button>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default GroceryList;
